// Build a clean Telegram alert from the incoming form email.
// Most contact forms send fields as "Label: value" lines.
// Edit the FIELDS list to match your form's labels.
const e = $input.first().json;
let raw = (e.text || '').toString();
if (!raw && e.html) raw = e.html.toString().replace(/<[^>]+>/g, '\n');
const lines = raw.split(/\r?\n/).map(l => l.replace(/ /g, ' ').trim()).filter(Boolean);

const FIELDS = [
  { label: 'Name', emoji: '🏷️' },
  { label: 'Email', emoji: '📧' },
  { label: 'Phone', emoji: '📱' },
  { label: 'Message', emoji: '💬' }
];

function field(label) {
  const re = new RegExp('^' + label + '\\s*:?\\s*(.*)$', 'i');
  for (let i = 0; i < lines.length; i++) {
    const m = lines[i].match(re);
    if (m) { let v = (m[1] || '').trim(); if (!v && lines[i + 1]) v = lines[i + 1].trim(); return v; }
  }
  return '';
}

const out = ['📬 New contact from your website', ''];
let found = 0;
for (const f of FIELDS) { const v = field(f.label); if (v) { out.push(f.emoji + ' ' + f.label + ': ' + v); found++; } }

if (!found) {
  const subject = (e.subject || '(no subject)').toString().trim();
  const body = (e.text || '').toString().trim().slice(0, 1500);
  return [{ json: { message: '📬 New contact from your website\n\nSubject: ' + subject + '\n\n' + body } }];
}
return [{ json: { message: out.join('\n') } }];
